  const tool = inventory.getToolEntry(toolName);
  if (!tool) {
    throw new Error(`Tool not found: ${toolName}`);
  }

  // Override clean-room mode if explicitly requested
  if (cleanRoom) {
    tool.cleanRoomRequired = true;
  }

  const manifest = new ManifestManager();
  const coordinator = new Coordinator();
  const tracker = createResourceTracker();
  const sessionRunner = new SessionRunner();
  const pool = new SessionPool(1);

  const sharedContext: SharedTestContext = {};

  const queueItem: TestQueueItem = {
    tool,
    priority: 0,
    prerequisites: [],
    addedAt: new Date(),
  };

  await pool.acquire();
  const testResult = await runTest(queueItem, sessionRunner, coordinator, manifest, tracker, pool, sharedContext, tool.domain);
  const durationMs = Date.now() - startTime;

  // Get the actual session result from the manifest
  const history = await manifest.getToolHistory(toolName);
  const latestEntry = history.length > 0 ? history[history.length - 1] : null;

  return {
    sessionId: latestEntry?.sessionId || testResult.testId,
    status: testResult.status,
    metrics: {
      durationMs: latestEntry?.durationMs || durationMs,
      totalCostUsd: 0, // Cost tracking would come from session
      numTurns: latestEntry?.toolCallCount || 0,
    },
    error: latestEntry?.errorMessage,
  };
}

/**
 * Get current harness status
 */
export function getStatus(): CoordinatorStatus {
  return { ...harnessState };
}

/**
 * Stop all running tests
 */
export async function stop(): Promise<void> {
  console.log('[harness] Stopping all tests...');
  harnessState.currentPhase = 'stopping';
  // In a real implementation, would signal all sessions to stop
}

